def validate_belief_sequence(script_text: str) -> dict:
    """Check that beliefs 1-4 appear in order with supporting structure."""
    beliefs = {
        1: {"keywords": ["root cause", "hidden cause", "real reason", "not your fault"], "found": False, "position": -1},
        2: {"keywords": ["failed because", "didn't work because", "old way", "why nothing worked"], "found": False, "position": -1},
        3: {"keywords": ["mechanism", "solution", "discovery", "breakthrough", "new approach"], "found": False, "position": -1},
        4: {"keywords": ["product", "created", "formulated", "designed", "introducing"], "found": False, "position": -1}
    }
    lines = script_text.lower().split('\n')
    for i, line in enumerate(lines):
        for belief_num, belief in beliefs.items():
            if not belief["found"] and any(kw in line for kw in belief["keywords"]):
                belief["found"] = True
                belief["position"] = i

    issues = []
    for num in range(1, 5):
        if not beliefs[num]["found"]:
            issues.append(f"Belief {num} not detected in script")
    for num in range(1, 4):
        if beliefs[num]["found"] and beliefs[num+1]["found"]:
            if beliefs[num]["position"] > beliefs[num+1]["position"]:
                issues.append(f"Belief {num} appears AFTER Belief {num+1} — sequence violation")

    return {"valid": len(issues) == 0, "issues": issues, "belief_positions": {k: v["position"] for k, v in beliefs.items()}}

def check_visual_coverage(two_column_script: list[dict]) -> dict:
    """Validate no naked audio lines exist in production script."""
    missing_visuals = []
    for i, row in enumerate(two_column_script):
        audio = row.get("audio", "").strip()
        visual = row.get("visual_direction", "").strip()
        if audio and not visual:
            missing_visuals.append(f"Row {i+1}: Audio without visual direction — '{audio[:50]}...'")
    return {
        "valid": len(missing_visuals) == 0,
        "coverage_pct": round((1 - len(missing_visuals) / max(len(two_column_script), 1)) * 100, 1),
        "missing": missing_visuals
    }

def audit_qa_spine(sentences: list[str]) -> dict:
    """Flag potential logic leaps between consecutive sentences."""
    connector_phrases = ["and the reason", "which means", "but you might", "so why", "that's because",
                         "in other words", "this is important because", "here's why", "the result"]
    gaps = []
    for i in range(len(sentences) - 1):
        current = sentences[i].lower()
        next_s = sentences[i+1].lower()
        has_connector = any(c in next_s for c in connector_phrases)
        shares_subject = bool(set(current.split()) & set(next_s.split()) - {"the", "a", "is", "and", "to", "of"})
        if not has_connector and not shares_subject:
            gaps.append({"line": i+1, "current": sentences[i][:60], "next": sentences[i+1][:60], "issue": "Potential logic leap"})
    return {"total_sentences": len(sentences), "potential_gaps": len(gaps), "gaps": gaps[:10]}

def calculate_belief_ratio(script_sections: dict) -> dict: """Measure belief-building vs product-pitch content ratio.""" belief_sections = ["hook", "lead", "rock_bottom", "authority", "ump", "ums"] pitch_sections = ["product_reveal", "offer", "urgency", "cta"] proof_section = ["testimonials"] # Counts as belief-building
belief_words = sum(len(script_sections.get(s, "").split()) for s in belief_sections + proof_section) pitch_words = sum(len(script_sections.get(s, "").split()) for s in pitch_sections) total = belief_words + pitch_words
ratio = round(belief_words / max(total, 1) * 100, 1) return { "belief_pct": ratio, "pitch_pct": round(100 - ratio, 1), "valid": ratio >= 75, # Allow 75-85% range "recommendation": "Add more mechanism education" if ratio < 75 else "Ratio is healthy" if ratio <= 85 else "May be under-selling — check offer section" }

def detect_bridge_pattern(ums_section: str, product_section: str) -> dict:
    """Check for named bridge pattern at mechanism-to-product transition."""
    bridge_signals = {
        "blind_solution": ["ritual", "molecule", "secret", "discovery", "ancient"],
        "problem_quick_fix": ["you'd have to", "impossible to", "but you'd need", "that's why I created"],
        "micro_commitment": ["would you agree", "would you try", "can we agree"],
        "identity_gap": ["people who", "those who", "the kind of person"],
        "three_option": ["option 1", "option 2", "option 3", "the hard way", "the smart way"]
    }
    combined = (ums_section + " " + product_section).lower()
    detected = [name for name, signals in bridge_signals.items() if any(s in combined for s in signals)]
    return {
        "bridge_found": len(detected) > 0,
        "detected_patterns": detected,
        "recommendation": "Add a bridge pattern between UMS and Product Reveal" if not detected else None
    }

def validate_proof_architecture(testimonial_section: str) -> dict:
    """Check proof section follows the avalanche pattern."""
    issues = []
    text = testimonial_section.lower()
    has_hero = any(kw in text for kw in ["case study", "story", "journey", "rock bottom", "transformation"])
    has_rapid = any(kw in text for kw in ["rapid fire", "montage", "quick cuts", "lost 10", "lost 20"])
    has_volume = any(kw in text for kw in ["scroll", "reviews", "comments", "trustpilot", "hundreds"])

    if not has_hero: issues.append("Missing Hero Case Study (deep-dive testimonial)")
    if not has_rapid: issues.append("Missing Rapid Fire Montage (demographic diversity)")
    if not has_volume: issues.append("Missing Scroll of Truth (volume/scale proof)")

    return {"valid": len(issues) == 0, "phases_detected": {"hero": has_hero, "rapid_fire": has_rapid, "volume": has_volume}, "issues": issues}

def audit_congruency(ad_headline: str, page_headline: str, vsl_first_line: str, ad_style: str, vsl_style: str) -> dict:
    """Verify congruency chain is unbroken."""
    issues = []
    ad_words = set(ad_headline.lower().split())
    page_words = set(page_headline.lower().split())
    overlap = ad_words & page_words - {"the", "a", "is", "and", "to", "of", "for", "in"}
    if len(overlap) < 2:
        issues.append(f"Low keyword overlap between ad and page headline ({len(overlap)} shared words)")
    if ad_style.lower() != vsl_style.lower():
        issues.append(f"Style mismatch: ad is '{ad_style}' but VSL is '{vsl_style}'")
    return {"congruent": len(issues) == 0, "issues": issues, "keyword_overlap": list(overlap)}

def check_conspiracy_compliance(script_text: str) -> dict:
    """Scan for language that may trigger ad platform moderation."""
    banned_patterns = {
        "lying to you": "Standard advice may be incomplete",
        "poisoning": "has limitations that aren't widely discussed",
        "government hiding": "hasn't received mainstream attention yet",
        "cures": "supports your body's natural",
        "doctors don't want": "many practitioners aren't yet aware of",
        "big pharma": "the conventional pharmaceutical approach",
        "they don't want you to know": "this research is relatively new"
    }
    flags = []
    for banned, safe in banned_patterns.items():
        if banned in script_text.lower():
            flags.append({"flagged": banned, "suggestion": safe})
    return {"compliant": len(flags) == 0, "flags": flags, "risk_level": "HIGH" if len(flags) > 2 else "MEDIUM" if flags else "LOW"}

def check_rent_payment(script_by_minute: dict[int, str]) -> dict:
    """Ensure every 60s block serves belief, dopamine, or future pacing."""
    rent_signals = {
        "belief": ["because", "root cause", "the reason", "this means", "the truth is"],
        "dopamine": ["but here's", "however", "the twist", "surprising", "imagine", "what if"],
        "future_pace": ["imagine", "picture yourself", "30 days from now", "this time next"]
    }
    deadbeat_minutes = []
    for minute, text in script_by_minute.items():
        text_lower = text.lower()
        pays_rent = any(any(s in text_lower for s in signals) for signals in rent_signals.values())
        if not pays_rent and len(text.split()) > 20:
            deadbeat_minutes.append(minute)
    return {
        "valid": len(deadbeat_minutes) == 0,
        "deadbeat_minutes": deadbeat_minutes,
        "recommendation": f"Minutes {deadbeat_minutes} may be filler — add belief, dopamine hit, or future pace" if deadbeat_minutes else "All minutes paying rent"
    }
